from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    ip_address = request.remote_addr
    user_agent = request.user_agent.string

    # Log the login attempt
    logging.info(f'Login attempt - Username: {username}, Password: {password}, Email: {email}, IP: {ip_address}, User Agent: {user_agent}')

    # Here you would add your authentication logic
    # For demonstration, we assume authentication is successful
    return jsonify({'message': 'Login successful'}), 200

if __name__ == '__main__':
    app.run(debug=True)